/* $Id$ */

#ifndef OLAS_LAPACKGBMATRIX_HH
#define OLAS_LAPACKGBMATRIX_HH

#include "graph/graph.hh"
#include "matvec/matvec.hh"
#include "utils/utils.hh"
#include "external/lapack/olasf77mapping.hh"
#include "external/lapack/lapackbasematrix.hh"

namespace OLAS {

  // some compilers insist on the declaration of this function
  // before it is introduced as a friend of LapackBaseMatrix
  // void test_lapackgbmatrix();

  //! This class is for general LAPACK matrices with banded storage.

  //! This class represents matrices using LAPACK's general banded storage
  //! scheme. The template parameter entryT defines, whether we have a matrix
  //! with real or complex entries. The question, if the entries are single
  //! or double precision is solved by comparing the size of Double resp.
  //! Complex with double and complex<double>.
  //! \htmlonly
  //! <center><img src="../AddDoc/lapack.jpg"></center>
  //! \endhtmlonly
  //! For further information see the
  //! <a href="http://www.netlib.org/lapack">LAPACK</a> pages at Netlib.
  //! \note
  //! - This matrix class is restricted to square matrices.
  //! - The amount of memory required to store an \f$n\times n\f$ matrix with
  //!   \f$w_u\f$ upper and \f$w_l\f$ lower diagonals is
  //!   \f$(w_l + 1 + w_u)\cdot n\f$ entries.
  template <class entryF, class entryC>
  class LapackGBMatrix : public LapackBaseMatrix {

    //! This class is strongly connected to us

    //! The LapackGBMatrix class is designed to allow using LAPACK for
    //! performing an LU factorisation. Thus, the corresponding OLAS class
    //! which represents the interface to the factorisation and solution
    //! routines is a friend of this class.
    friend class Lapack_LU;

  public:

    //! Standard constructor

    //! This is the constructor designed to be called by the
    //! GenerateStdMatrixObject function. Since banded storage is used a
    //! fill value is meaningless and not required. It is only provided as
    //! (optional) argument for constistency reasons.
    LapackGBMatrix( Integer nrows, Integer ncols, MatrixEntryType entryType ) {
      ENTER_FCN( "LapackGBMatrix::LapackGBMatrix" );
      nrows_ = nrows;
      ncols_ = ncols;
      data_ = NULL;
      myEntryType_ = entryType;

      // Set internal auxilliary attributes
      nrowsact_ = 0;
      offset_ = 0;
      amEnlarged_ = false;

      // Ensure that matrix is square
      if ( nrows_ != ncols_ ) {
        Error( "Request for a non-square LapackGBMatrix", __FILE__, __LINE__ );
      }
    }

    //! Destructor

    //! This is the default destructor. It needs to be deep, since the
    //! class dynamically allocates memory for the matrix entries.
    ~LapackGBMatrix() {
      ENTER_FCN( "LapackGBMatrix::~LapackGBMatrix" );
      DeleteArray(data_);
    }

    //! Convert a CRS_Matrix into a LapackGBMatrix

    //! This method allows the conversion from a CRS_Matrix into a
    //! LapackGBMatrix. Therefore the matrix must be created using the
    //! default constructor with the number of rows, number of columns,
    //! and entry type, followed immediately by the call of Convert. Do
    //! not call SetSparsityPattern. The sparsity pattern is set by this
    //! routine.
    void Convert( const CRS_Matrix<entryC>& A );

    //! Setup the sparsity pattern of the matrix

    //! This method uses the graph to generate the internal information needed
    //! for representing the matrix correctly. Since we use the banded storage
    //! format the information queried from the graph is the lower and upper
    //! bandwidth of the matrix. This is required to perform memory allocation.
    //! Before this function has not been called the matrix is not ready to be
    //! used, if the object has been generated by the standard constructor.
    void SetSparsityPattern( BaseGraph &graph );

    //! Initialize matrix to zero
    
    //! This methods sets all matrix entries to zero. In the case of the
    //! LapackGBMatrix this concerns all matrix entries inside the lower
    //! and upper band.
    void Init();

    //! Set value of a matrix entry

    //! This method sets the value of the matrix entry at position (i,j) to v.
    //! Note that the input argument v currently can only be either Double or
    //! Complex. The argument v will be cast to the entry type entryT and thus
    //! the fitting interface must be called.
    void SetMatrixEntry( Integer i, Integer j, entryC &v );

    //! Add value to a matrix entry

    //! This method adds the value v to the matrix entry at position (i,j).
    //! Note that the input argument v currently can only be either Double or
    //! Complex. The argument v will be cast to the entry type entryT and thus
    //! the fitting interface must be called.
    void AddToMatrixEntry( Integer i, Integer j, entryC &v );
  
    //! Return the storage type of the matrix
  
    //! The method returns the storagfe type of the matrix. This is encoded
    //! as a value of the enumeration data type MatrixStorageType. In the
    //! case of this class the return value is of course LAPACK_GBMATRIX.
    MatrixStorageType GetStorageType() const {
      ENTER_IFCN( "LapackGBMatrix::GetStorageType" );
      return LAPACK_GBMATRIX;
    }

    //! Return the Entry type of the matrix
  
    //! The method returns the entry type of the matrix (i.e. Double, Complex,
    //! or whatever it is). This is encoded as a value of the enumeration data
    //! type MatrixEntryType. 
    MatrixEntryType GetEntryType() const {
      return myEntryType_;
    };

    //! Return the upper bandwidth of the matrix

    //! The method returns the upper bandwidth of the matrix as obtained
    //! from the graph via SetSparsityPattern.
    Integer GetUpperBandwidth() const {
      return wupper_;
    }

    //! Return the lower bandwidth of the matrix

    //! The method returns the lower bandwidth of the matrix as obtained
    //! from the graph via SetSparsityPattern.
    Integer GetLowerBandwidth() const {
      return wlower_;
    }

    //! Export the matrix to a file in MatrixMarket format

    //! The method will export the matrix to an ascii file according to the
    //! MatrixMarket specifications. Since the matrix is stored in LAPACK's
    //! general banded storage format the output format will be general,
    //! co-ordinate, real or complex. For details of the specification see
    //! http://math.nist.gov/MatrixMarket .
    //! Note that we check the matrix entries and only store values that are
    //! not identical to zero.
    //! \param fname name of output file
    //! \param comment string to be inserted into file header
    void Export( const Char *fname, const Char *comment = NULL ) const;

    //! Add the multiple of a matrix to this matrix.

    //! The method adds the multiple of a matrix to this matrix. In doing so
    //! the bandwidth of the matrix mat is assumed to be identical to the
    //! bandwidth of this matrix.
    void Add( const Double a, const StdMatrix& mat);

    //! Returns the largest modulus of a diagonal entry

    //! The method determines the entry on the main diagonal of the matrix
    //! which possesses the largest absolute value and returns its modulus.
    Double GetMaxDiag() const;

    //! Set a diagonal entry

    //! This method sets the value of the diagonal entry of the i-th
    //! row of the matrix to the value given by the paramter v.
    //! This method sets the needsAssembly_ attribute to true.
    void SetDiagEntry( Integer i, entryC &v );

    //! Query a diagonal entry

    //! This method returns in v the value of the diagonal entry of the i-th
    //! row of the matrix.
    void GetDiagEntry( Integer i, entryC &v ) const;

    //! Method to force instantiation of all public member functions
    void InstantiatePublicMethods();

    //! Get the number of matrix rows on scalar level

    //! The method returns the number of rows of the matrix on the scalar
    //! level, i.e. the count is not based upon the stored entry type but
    //! accumulated over the scalar real/complex entries.
    //! \return The same value as GetNrows(), since LapackGBMatrices only
    //!         store scalar entries anyhow.
    Integer GetNrowsScalar() const {
      ENTER_IFCN( "LapackGBMatrix::GetNrowsScalar" );
      return nrows_;
    }

    //! Get the number of matrix columns on scalar level

    //! The method returns the number of columns of the matrix on the scalar
    //! level, i.e. the count is not based upon the stored entry type but
    //! accumulated over the scalar real/complex entries.
    //! \return The same value as GetNcols(), since LapackGBMatrices only
    //!         store scalar entries anyhow.
    Integer GetNcolsScalar() const {
      ENTER_IFCN( "LapackGBMatrix::GetNcolsScalar" );
      return ncols_;
    }

  private:

    //! Default Constructor

    //! Use of the default constructor is not intended and thus
    //! forbidden.
    LapackGBMatrix(){
      Error( "LapackGBMatrix: Private constructor was called!", __FILE__,
             __LINE__ );
    };

    //! Alternative Constructor

    //! This is an alternative constructor designed to be called by the
    //! Lapack_LU class instead of the standard constructor. This version will
    //! setup the internal data structures directly making it unnecessary to
    //! call SetSparsityPattern. It will also allocate \f$w_l\f$ additional
    //! rows as storage space.
    //! \param nrows number of rows of the matrix
    //! \param ncols number of columns of the matrix
    //! \param wlower lower bandwidth, i.e. number of non-zero sub-diagonals
    //! \param wupper upper bandwidth, i.e. number of non-zero super-diagonals
    //! \param etype type of matrix entries
    LapackGBMatrix( Integer nrows, Integer ncols, Integer wlower,
                    Integer wupper, MatrixEntryType etype );

    //! Vector with matrix entries

    //! This vector contains the matrix entries in LAPACK's banded
    //! storage format. The data are stored in row major ordering,
    //! so that this vector can directly be passed to the FORTRAN routines.
    entryF *data_;

    //! Length of data array
    Integer length_;

    //! Lower bandwidth of matrix
    UInt wlower_;

    //! Upper bandwidth of matrix
    UInt wupper_;

    //! Auxilliary value

    //! This is an auxilliary value for internal computations. It stores the
    //! number of columns of the packed banded matrix. Thus, this value
    //! corresponds to the offset of the column starts in the data vector.
    //! If the matrix does not contain additional storage space (see also
    //! the amEnlarged_ attribute) we have \f$\mbox{offset} = w_l + 1 + w_u\f$,
    //! otherwise it is \f$\mbox{offset} = 2w_l + 1 + w_u\f$.
    Integer nrowsact_;

    //! Auxilliary value

    //! This is an auxilliary value for internal computations. For the actual
    //! LU factorisation we need a matrix with additional storage space of
    //! \f$w_l\f$ rows, where \f$w_l\f$ is the lower bandwidth. The actual
    //! matrix entries are then stored in rows \f$(w_l + 1)\f$ to
    //! \f$(2 w_l + w_u + 1)\f$. This attribute keeps track on whether the
    //! matrix contains this additional storage space or not.
    bool amEnlarged_;

    //! Auxilliary value

    //! This is an auxilliary value for internal computations. For the actual
    //! LU factorisation we need a matrix with additional storage space of
    //! \f$w_l\f$ rows, where \f$w_l\f$ is the lower bandwidth. The actual
    //! matrix entries are then stored in rows \f$(w_l + 1)\f$ to
    //! \f$(2 w_l + w_u + 1)\f$. This attribute stores the corresponding offset
    //! used in the index computation in the Index method if the matrix has
    //! such work space attached to it.
    Integer offset_;

    //! Mapping of matrix indices to indices in data vector

    //! This method takes care of the computation of the correct index position
    //! in the data vector for a certain matrix entry \f$a_{ij}\f$. Following
    //! the specification of the banded storage format \f$a_{ij}\f$ is mapped
    //! to \f$A(w_u+1+i-j,j)\f$ where \f$w_u\f$ is the number of
    //! super-diagonals of the matrix. The resulting value is then serialised
    //! taking FORTRAN's row-major ordering into account.
    inline Integer Index( Integer i, Integer j ) const {
      return (j-1) * nrowsact_ + (wupper_ + 1 + (i+offset_) - j);
    }

    //! Return pointer to data vector

    //! A call to this method returns the starting address of the data vector
    //! containing the matrix entries. Note that this is the real starting
    //! address of the allocated memory block without offset.
    entryF *GetDataPointer0() {

#ifdef DEBUG_LAPACKGBMATRIX
      if ( data_ == NULL ) {
        Error( "LapackGBMatrix::GetDataPointer0 data_ has not been allocated!",
               __FILE__, __LINE__ );
      }
#endif

      return data_ + 1;
    }

    //! Return pointer to data vector

    //! A call to this method returns the starting address of the data vector
    //! containing the matrix entries. Note that this is the real starting
    //! address of the allocated memory block without offset. This is the
    //! "const" version of the method.
    entryF *GetDataPointer0() const {

#ifdef DEBUG_LAPACKGBMATRIX
      if ( data_ == NULL ) {
        Error( "LapackGBMatrix::GetDataPointer0 data_ has not been allocated!",
               __FILE__, __LINE__ );
      }
#endif

      return data_ + 1;
    }

    //! Auxilliary function for Export method

    //! This method is an auxilliary function called by the Export method.
    //! It takes care of the difference in testing real/complex values for
    //! identity with zero and the different way of outputting them. This
    //! is achieved by an explicit specialisation for the F77complex8 and
    //! F77complex16 case.
    void WriteEntries( FILE *fp ) const;

    //! Entry type of instantiation of this tmeplate class

    //! This attribute contains the entry type of an instantiation of this
    //! template class as a value of the enumeration data type MatrixEntryType.
    MatrixEntryType myEntryType_;

    //! Auxilliary friendship relation (temporary?)

    //! This function is a friend of this class, so that it can call the
    //! private alternate constructor and thus triggers its template
    //! instantiation.
    // friend void test_lapackgbmatrix();

  };

}

#endif
